/// Read-only access to persisted [Order] aggregates.
class OrderRepository {
  /// Loads an order by its identifier.
  Future<Order> findById(String id) async => Order(id);
}

/// A purchase order recorded in the system of record.
class Order {
  /// Creates an order with the supplied [id].
  Order(this.id);

  /// The opaque, server-assigned order identifier.
  final String id;
}

/// Read-only access to persisted [_Order] aggregates.
class OrderRepository {
  Future<_Order> _findById(String id) async => _Order(id);
}

class _Order {
  _Order(this.id);
  final String id;
}
